import{_ as a,o as r,c as t,a0 as l}from"./chunks/framework.jwovEGr5.js";const p=JSON.parse('{"title":"Set Up Reward Rules","description":"","frontmatter":{},"headers":[],"relativePath":"how-to/reward-rules.md","filePath":"how-to/reward-rules.md"}'),i={name:"how-to/reward-rules.md"};function o(s,e,n,d,h,c){return r(),t("div",null,[...e[0]||(e[0]=[l('<h1 id="set-up-reward-rules" tabindex="-1">Set Up Reward Rules <a class="header-anchor" href="#set-up-reward-rules" aria-label="Permalink to &quot;Set Up Reward Rules&quot;">​</a></h1><p><strong>Reward rules</strong> are the configuration step behind the rewards system. They tell the app what counts as reward-worthy performance.</p><p>This guide is for <code>Supreme Admin</code>, <code>King</code>, and <code>Alliance Leader</code> users who are allowed to manage reward settings. If you only need to review the final output, go to <a href="./rewards.html">Review Reward Eligibility</a>.</p><blockquote><p>Screenshot placeholder: <code>reward-rules.png</code> (S56)</p></blockquote><h2 id="what-reward-rules-do" tabindex="-1">What reward rules do <a class="header-anchor" href="#what-reward-rules-do" aria-label="Permalink to &quot;What reward rules do&quot;">​</a></h2><p>A reward rule looks at saved analytics and decides who should be marked as eligible for a reward. That can be based on things like:</p><ul><li>minimum points</li><li>minimum participation percentage</li><li>which events count</li><li>how many missed events are still acceptable</li><li>the time period being checked</li></ul><p>This is the setup step. The app then uses those rules to build the output you read on the <a href="./rewards.html">Rewards</a> page.</p><h2 id="open-the-page" tabindex="-1">Open the page <a class="header-anchor" href="#open-the-page" aria-label="Permalink to &quot;Open the page&quot;">​</a></h2><p>Open <strong>Settings</strong> and then <strong>Rewards</strong>.</p><p>Depending on your role, you may be able to create rules at kingdom scope, alliance scope, or both.</p><h2 id="what-you-can-set" tabindex="-1">What you can set <a class="header-anchor" href="#what-you-can-set" aria-label="Permalink to &quot;What you can set&quot;">​</a></h2><p>The rules page includes fields such as:</p><ul><li>rule key and label</li><li>minimum points</li><li>minimum participation percentage</li><li>included events</li><li>maximum missed events</li><li>period</li><li>icon, color, and priority</li><li>whether the rule is enabled</li></ul><p>There is also a <strong>Preview</strong> area so you can check what a rule is meant to represent before relying on it.</p><h2 id="scope-matters" tabindex="-1">Scope matters <a class="header-anchor" href="#scope-matters" aria-label="Permalink to &quot;Scope matters&quot;">​</a></h2><p>Reward rules can be tied to:</p><ul><li>a whole kingdom</li><li>one alliance inside that kingdom</li></ul><p>Set the scope carefully. A kingdom rule affects a wider audience than an alliance rule.</p><h2 id="recalculate-after-changes" tabindex="-1">Recalculate after changes <a class="header-anchor" href="#recalculate-after-changes" aria-label="Permalink to &quot;Recalculate after changes&quot;">​</a></h2><p>After changing rules, use the available recalculation action if the rewards output does not refresh right away. This helps the app rebuild eligibility from the updated rule set.</p><h2 id="good-practice" tabindex="-1">Good practice <a class="header-anchor" href="#good-practice" aria-label="Permalink to &quot;Good practice&quot;">​</a></h2><ul><li>Keep rule names clear so leaders can understand them on the rewards page.</li><li>Start simple before creating many overlapping rules.</li><li>Review <a href="./../getting-started/glossary.html#reward-eligibility">reward eligibility</a> after major rule changes.</li><li>Treat this page as the rule setup step and <a href="./rewards.html">Rewards</a> as the review-and-handle step.</li></ul>',23)])])}const m=a(i,[["render",o]]);export{p as __pageData,m as default};
